import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    include: ['src/**/*.spec.ts'],
    globals: true,
    coverage: {
      provider: 'v8',
      reporter: ['json-summary', 'text'],
      include: ['src/**/*.ts'],
      exclude: ['src/**/*.spec.ts'],
    },
  },
});

import { describe, it, expect } from "vitest";
import { claimOffice } from "./claim-office.js";

describe("Claim Office", () => {
  // =========================================================================
  // QUOTE: Edge cases
  // =========================================================================

  describe("quote — edge cases", () => {
    it.todo(
      "should return premium 5 G for an empty item list — only the processing fee"
    );

    it.todo(
      "should return an error for an unknown item type (e.g. broomstick)"
    );
  });

  // =========================================================================
  // QUOTE: Single-item base premiums
  // =========================================================================

  describe("quote — single item base premiums", () => {
    it.todo(
      "should return premium 105 G for a single sword — 100 G base + 5 G fee"
    );

    it.todo(
      "should return premium 65 G for a single amulet — 60 G base + 5 G fee"
    );

    it.todo(
      "should return premium 85 G for a single staff — 80 G base + 5 G fee"
    );

    it.todo(
      "should return premium 45 G for a single potion — 40 G base + 5 G fee"
    );
  });

  // =========================================================================
  // QUOTE: Component base premiums
  // =========================================================================

  describe("quote — component base premiums", () => {
    it.todo(
      "should return premium 30 G for 1 rune — 25 G base + 5 G fee"
    );

    it.todo(
      "should return premium 55 G for 2 runes — 50 G base + 5 G fee"
    );

    it.todo(
      "should return premium 65 G for 3 runes — 60 G block base + 5 G fee"
    );

    it.todo(
      "should return premium 105 G for 4 runes — 100 G base (no block) + 5 G fee"
    );

    it.todo(
      "should return premium 180 G for 7 runes — 175 G base + 5 G fee"
    );
  });

  // =========================================================================
  // QUOTE: "Alike" components (different types do not form blocks)
  // =========================================================================

  describe("quote — alike components", () => {
    it.todo(
      "should return premium 80 G for 2 runes + 1 moonstone — 75 G base (no block, different types) + 5 G fee"
    );

    it.todo(
      "should return premium 125 G for 3 runes + 3 moonstones — 120 G base (two separate blocks) + 5 G fee"
    );
  });

  // =========================================================================
  // QUOTE: Item-specific modifiers — cursed surcharge
  // =========================================================================

  describe("quote — cursed surcharge", () => {
    it.todo(
      "should return premium 155 G for a cursed sword — 100 G base + 50 G curse (50%) + 5 G fee"
    );
  });

  // =========================================================================
  // QUOTE: Item-specific modifiers — high enchantment surcharge
  // =========================================================================

  describe("quote — high enchantment surcharge", () => {
    it.todo(
      "should apply high-enchantment surcharge for sword with enchantment exactly 5 — 100 + 30 = 130 G base + 5 G fee = 135 G"
    );

    it.todo(
      "should not apply high-enchantment surcharge for sword with enchantment 4 — 100 G base + 5 G fee = 105 G"
    );
  });

  // =========================================================================
  // QUOTE: Modifier scope on multi-item policies
  // =========================================================================

  describe("quote — modifier scope on multi-item policies", () => {
    it.todo(
      "should apply cursed surcharge only to the cursed item — cursed sword + plain amulet: 100 + 50 (curse) + 60 = 210 G before policy modifiers, + 5 G fee = 215 G"
    );
  });

  // =========================================================================
  // QUOTE: Policy-wide modifiers — loyalty discount
  // =========================================================================

  describe("quote — loyalty discount", () => {
    it.todo(
      "should apply loyalty discount for customer with exactly 2 years — 20% discount on policy base premium"
    );

    it.todo(
      "should not apply loyalty discount for customer with less than 2 years"
    );
  });

  // =========================================================================
  // QUOTE: Policy-wide modifiers — first insurance surcharge
  // =========================================================================

  describe("quote — first insurance surcharge", () => {
    it.todo(
      "should apply 10% first insurance surcharge on the first quote — sword: 100 + 10 = 110 G + 5 G fee = 115 G"
    );

    it.todo(
      "should apply first insurance surcharge even for long-standing customers — each item in a quote is treated as a first insurance regardless of history"
    );
  });

  // =========================================================================
  // QUOTE: Policy-wide modifiers — follow-up contract discount
  // =========================================================================

  describe("quote — follow-up contract discount", () => {
    it.todo(
      "should apply 15% follow-up discount on the second quote — applied to policy base premium"
    );
  });

  // =========================================================================
  // QUOTE: Rounding premiums in MHPCO's favor (up)
  // =========================================================================

  describe("quote — rounding", () => {
    it.todo(
      "should round premium up — a calculation yielding 197.5 G results in 198 G"
    );

    it.todo(
      "should keep intermediate amounts as fractions and only round the final premium"
    );
  });

  // =========================================================================
  // QUOTE: Integration examples
  // =========================================================================

  describe("quote — integration: newcomer with cursed sword", () => {
    it.todo(
      "should return premium 165 G — 100 base + 50 curse + 10 first insurance = 160 + 5 fee = 165 G (customer: 0 years, no previous contract, cursed steel sword ench 3)"
    );
  });

  describe("quote — integration: long-standing customer second contract", () => {
    it.todo(
      "should return premium 160 G — 100 base + 50 curse + 30 high-ench - 20 loyalty + 10 first insurance - 15 follow-up = 155 + 5 fee = 160 G (customer: 3 years, second quote, cursed steel sword ench 7)"
    );
  });

  // =========================================================================
  // CLAIM: Standard reimbursement (no special clauses)
  // =========================================================================

  describe("claim — standard reimbursement", () => {
    it.todo(
      "should return payout 400 G for regular sword (steel, ench 3) with damage 500 G — full reimbursement minus 100 G deductible"
    );

    it.todo(
      "should return payout 100 G for rune with damage 200 G — full reimbursement minus 100 G deductible (no enchantment/material)"
    );
  });

  // =========================================================================
  // CLAIM: Deductible per damage event (multiple items in one claim)
  // =========================================================================

  describe("claim — deductible per damage event", () => {
    it.todo(
      "should return payout 600 G for dragon attack damaging sword (500 G) and amulet (300 G) — 100 G deductible per damaged item: (500-100) + (300-100) = 600 G"
    );
  });

  // =========================================================================
  // CLAIM: Enchantment >= 8 (50% reimbursement)
  // =========================================================================

  describe("claim — high enchantment clause", () => {
    it.todo(
      "should return payout 400 G for steel sword ench 9, damage 1000 G — 50% of 1000 = 500, minus 100 deductible = 400 G"
    );
  });

  // =========================================================================
  // CLAIM: Dragon material (full reimbursement)
  // =========================================================================

  describe("claim — dragon material clause", () => {
    it.todo(
      "should return payout 700 G for dragon-material sword ench 5, damage 800 G — full reimbursement minus 100 deductible: 800 - 100 = 700 G"
    );
  });

  // =========================================================================
  // CLAIM: Both clauses apply — 50% wins, then deductible
  // =========================================================================

  describe("claim — enchantment vs dragon material interaction", () => {
    it.todo(
      "should return payout 400 G for dragon-material sword ench 9, damage 1000 G — both clauses: 50% wins (500), then deductible (500 - 100) = 400 G"
    );

    it.todo(
      "should return payout 400 G for dragon-material sword ench 8, damage 1000 G — both clauses: 50% wins (500), then deductible (500 - 100) = 400 G"
    );
  });

  // =========================================================================
  // CLAIM: Multiple items of the same type
  // =========================================================================

  describe("claim — multiple items same type", () => {
    it.todo(
      "should compute insurance sum 2000 G and cap 4000 G for two swords"
    );

    it.todo(
      "should apply separate deductibles when both swords are damaged in a dragon attack"
    );

    it.todo(
      "should return an error when damages contain more entries of a type than the policy covers"
    );
  });

  // =========================================================================
  // CLAIM: Cap exhaustion
  // =========================================================================

  describe("claim — cap exhaustion", () => {
    it.todo(
      "should compute insurance sum 1600 G and cap 3200 G for a sword + amulet policy"
    );

    it.todo(
      "should compute cap 2000 G for a cursed sword — cap based on unmodified insurance value 1000 G, not premium"
    );

    it.todo(
      "should compute insurance sum 1750 G for a sword + 3 runes block — block discount affects premium only, not insurance sum"
    );

    it.todo(
      "should return payout 1400 G on first claim of 1500 G for a sword policy (cap 2000 G) — remaining cap 600 G"
    );

    it.todo(
      "should return payout 600 G on second claim of 1500 G after first claim exhausted 1400 G — remaining cap 0 G"
    );
  });

  // =========================================================================
  // CLAIM: Rounding payouts in MHPCO's favor (down)
  // =========================================================================

  describe("claim — rounding", () => {
    it.todo(
      "should round payout down — a calculation yielding 350.5 G results in 350 G"
    );
  });

  // =========================================================================
  // CLAIM: Edge cases
  // =========================================================================

  describe("claim — edge cases", () => {
    it.todo(
      "should return an error when claim references an item not in the policy"
    );

    it.todo(
      "should return an error when claim contains a negative damage amount"
    );
  });
});

