const KNOWN_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];

function validateItemTypes(items: any[]): void {
  for (const item of items) {
    if (!KNOWN_TYPES.includes(item.type)) {
      throw new Error(`Unknown item type: ${item.type}`);
    }
  }
}

const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

function basePremium(item: any): number {
  return BASE_PREMIUMS[item.type] ?? 0;
}

const COMPONENT_TYPES = ["rune", "moonstone"];
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

export function claimOffice(input: any): unknown {
  const results = [];
  for (const step of input.steps) {
    validateItemTypes(step.items);
    let premium = PROCESSING_FEE;

    const components = step.items.filter((i: any) => COMPONENT_TYPES.includes(i.type));
    const nonComponents = step.items.filter((i: any) => !COMPONENT_TYPES.includes(i.type));

    for (const item of nonComponents) {
      premium += basePremium(item);
    }

    if (components.length === BLOCK_SIZE && components.every((c: any) => c.type === components[0].type)) {
      premium += BLOCK_PREMIUM;
    } else {
      for (const item of components) {
        premium += basePremium(item);
      }
    }

    results.push({ premium });
  }
  return { results };
}

