content.content:
1	const KNOWN_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
2	
3	function validateItemTypes(items: any[]): void {
4	  for (const item of items) {
5	    if (!KNOWN_TYPES.includes(item.type)) {
6	      throw new Error(`Unknown item type: ${item.type}`);
7	    }
8	  }
9	}
10	
11	const INSURANCE_VALUES: Record<string, number> = {
12	  sword: 1000,
13	  amulet: 600,
14	  staff: 800,
15	  potion: 400,
16	  rune: 250,
17	  moonstone: 250,
18	};
19	
20	const DEDUCTIBLE = 100;
21	
22	const PROCESSING_FEE = 5;
23	
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	
33	function basePremium(item: any): number {
34	  return BASE_PREMIUMS[item.type] ?? 0;
35	}
36	
37	const COMPONENT_TYPES = ["rune", "moonstone"];
38	const BLOCK_SIZE = 3;
39	const BLOCK_PREMIUM = 60;
40	
41	function isComponent(item: any): boolean {
42	  return COMPONENT_TYPES.includes(item.type);
43	}
44	
45	function groupByType(items: any[]): Record<string, any[]> {
46	  const result: Record<string, any[]> = {};
47	  for (const item of items) {
48	    if (!result[item.type]) result[item.type] = [];
49	    result[item.type].push(item);
50	  }
51	  return result;
52	}
53	
54	function componentGroupPremium(group: any[]): number {
55	  if (group.length === BLOCK_SIZE) return BLOCK_PREMIUM;
56	  return group.reduce((sum: number, item: any) => sum + basePremium(item), 0);
57	}
58	
59	function countByType(entries: any[], typeKey: string): Record<string, number> {
60	  const counts: Record<string, number> = {};
61	  for (const entry of entries) {
62	    const type = entry[typeKey];
63	    counts[type] = (counts[type] ?? 0) + 1;
64	  }
65	  return counts;
66	}
67	
68	function validateDamageCoverage(damages: any[], policyItems: any[]): void {
69	  const damageCounts = countByType(damages, "itemType");
70	  const policyCounts = countByType(policyItems, "type");
71	  for (const [type, count] of Object.entries(damageCounts)) {
72	    if (count > (policyCounts[type] ?? 0)) {
73	      throw new Error(`Damages exceed policy coverage for type: ${type}`);
74	    }
75	  }
76	}
77	
78	function calculatePayout(damages: any[], policyItems: any[]): number {
79	  let payout = 0;
80	  for (const damage of damages) {
81	    const matchingItem = policyItems.find((item: any) => item.type === damage.itemType);
82	    let reimbursement = damage.amount;
83	    if (matchingItem && matchingItem.enchantment >= 8) {
84	      reimbursement = damage.amount * 0.5;
85	    }
86	    payout += reimbursement - DEDUCTIBLE;
87	  }
88	  return payout;
89	}
90	
91	function processClaim(
92	  step: any,
93	  policyItems: any[],
94	  remainingCaps: Record<number, number>,
95	): { payout: number; remainingCap: number } {
96	  for (const damage of step.incident.damages) {
97	    if (damage.amount < 0) {
98	      throw new Error("Negative damage amount");
99	    }
100	  }
101	
102	  validateDamageCoverage(step.incident.damages, policyItems);
103	
104	  const insuranceSum = policyItems.reduce(
105	    (sum: number, item: any) => sum + (INSURANCE_VALUES[item.type] ?? 0),
106	    0,
107	  );
108	  const cap = 2 * insuranceSum;
109	  if (remainingCaps[step.policy] === undefined) {
110	    remainingCaps[step.policy] = cap;
111	  }
112	
113	  let payout = calculatePayout(step.incident.damages, policyItems);
114	  if (payout > remainingCaps[step.policy]) {
115	    payout = remainingCaps[step.policy];
116	  }
117	  payout = Math.floor(payout);
118	  remainingCaps[step.policy] -= payout;
119	
120	  return { payout, remainingCap: remainingCaps[step.policy] };
121	}
122	
123	function calculateItemSurcharges(items: any[]): number {
124	  let surcharges = 0;
125	
126	  for (const item of items) {
127	    if (isComponent(item)) continue;
128	    const base = basePremium(item);
129	    if (item.cursed) {
130	      surcharges += base * 0.5;
131	    }
132	    if (item.enchantment >= 5) {
133	      surcharges += base * 0.3;
134	    }
135	  }
136	
137	  return surcharges;
138	}
139	
140	function calculateRawPolicyBase(items: any[]): number {
141	  const components = items.filter(isComponent);
142	  const nonComponents = items.filter((i: any) => !isComponent(i));
143	
144	  let rawPolicyBase = 0;
145	  for (const item of nonComponents) {
146	    rawPolicyBase += basePremium(item);
147	  }
148	  for (const group of Object.values(groupByType(components))) {
149	    rawPolicyBase += componentGroupPremium(group);
150	  }
151	
152	  return rawPolicyBase;
153	}
154	
155	function processQuote(
156	  step: any,
157	  customer: any,
158	  quoteCount: number,
159	): { premium: number } {
160	  validateItemTypes(step.items);
161	
162	  const rawPolicyBase = calculateRawPolicyBase(step.items);
163	  const itemSurcharges = calculateItemSurcharges(step.items);
164	
165	  let policyWideModifier = rawPolicyBase * 0.1;
166	
167	  if (customer.yearsWithMHPCO >= 2) {
168	    policyWideModifier -= rawPolicyBase * 0.2;
169	  }
170	
171	  if (quoteCount > 1) {
172	    policyWideModifier -= rawPolicyBase * 0.15;
173	  }
174	
175	  const premium = Math.ceil(rawPolicyBase + itemSurcharges + policyWideModifier + PROCESSING_FEE);
176	
177	  return { premium };
178	}
179	
180	export function claimOffice(input: any): unknown {
181	  const results = [];
182	  const quoteSteps: any[] = [];
183	  const remainingCaps: Record<number, number> = {};
184	  let quoteCount = 0;
185	
186	  for (const step of input.steps) {
